<div class="d-flex justify-content-between align-items-center mb-4"><div><h1 class="h3">Tax & discount rules</h1><p class="text-muted">Centralized pricing rules applied by customer type, service, or territory.</p></div></div><div class="row g-4"><div class="col-xl-5"><div class="card"><div class="card-body"><h2 class="h5">Add rule</h2><form method="post"><?=csrf_field()?><div class="mb-2"><label>Name</label><input class="form-control" name="name" required></div><div class="row g-2"><div class="col"><select class="form-select" name="rule_type"><option value="tax">Tax</option><option value="discount">Discount</option></select></div><div class="col"><select class="form-select" name="calculation_type"><option value="percentage">Percentage</option><option value="fixed">Fixed</option></select></div></div><div class="row g-2 mt-1"><div class="col"><input class="form-control" type="number" step="0.0001" name="amount" placeholder="Amount" required></div><div class="col"><input class="form-control" type="number" name="priority" value="100"></div></div><div class="mt-2"><select class="form-select" name="applies_to"><option value="all">All</option><option value="residential">Residential</option><option value="commercial">Commercial</option><option value="service">Service</option><option value="territory">Territory</option></select></div><div class="mt-2"><input class="form-control" type="number" name="reference_id" placeholder="Reference ID, when applicable"></div><div class="form-check mt-2"><input class="form-check-input" type="checkbox" name="active" checked><label class="form-check-label">Active</label></div><button class="btn btn-primary mt-3">Save rule</button></form></div></div></div><div class="col-xl-7"><div class="card"><div class="card-body"><div class="table-responsive"><table class="table align-middle"><thead><tr><th>Name</th><th>Type</th><th>Amount</th><th>Applies</th><th>Status</th></tr></thead><tbody><?php foreach($rules as $r):?><tr><td><?=e($r['name'])?></td><td><?=e($r['rule_type'])?></td><td><?=e($r['amount'])?><?= $r['calculation_type']==='percentage'?'%':''?></td><td><?=e($r['applies_to'])?></td><td><?= $r['active']?'Active':'Inactive'?></td></tr><?php endforeach?></tbody></table></div></div></div></div></div>
